import{_ as t,o as r,c as s,a3 as i}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Score Distributeur","description":"","frontmatter":{"title":"Score Distributeur"},"headers":[],"relativePath":"publishers/score-distributor.md","filePath":"publishers/score-distributor.md"}'),o={name:"publishers/score-distributor.md"};function a(n,e,l,u,c,d){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="score-distributeur" tabindex="-1">Score Distributeur <a class="header-anchor" href="#score-distributeur" aria-label="Permalink to &quot;Score Distributeur&quot;">​</a></h1><p>Votre Score Distributeur détermine votre visibilité auprès des annonceurs — et donc le volume de campagnes que vous recevez. Comprenez-le pour maximiser vos revenus.</p><h2 id="c-est-quoi-le-score-distributeur" tabindex="-1">C&#39;est quoi le Score Distributeur ? <a class="header-anchor" href="#c-est-quoi-le-score-distributeur" aria-label="Permalink to &quot;C&#39;est quoi le Score Distributeur ?&quot;">​</a></h2><p>Le Score Distributeur est une <strong>note sur 5 étoiles</strong> qui évalue la qualité et la fiabilité de votre profil sur la plateforme getinside.</p><p>Il est recalculé <strong>dynamiquement</strong> en temps réel et <strong>détermine votre classement dans le moteur de recherche</strong> que les annonceurs utilisent pour choisir leurs distributeurs.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Un score élevé = plus de visibilité = plus de propositions de campagnes = plus de revenus.</p></div><h2 id="impact-selon-votre-score" tabindex="-1">Impact selon votre score <a class="header-anchor" href="#impact-selon-votre-score" aria-label="Permalink to &quot;Impact selon votre score&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card" style="border-color:var(--gi-tint-red-text);background:var(--gi-tint-red-bg);"><strong style="color:var(--gi-tint-red-text);">⭐⭐ Moins de 3/5</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Audience <strong>peu visible</strong>. Risque de ne plus recevoir de propositions de campagnes.</p><p style="margin:0.5rem 0 0;font-size:0.8rem;color:var(--gi-tint-red-text);font-weight:600;">Action immédiate requise.</p></div><div class="gi-value-card"><strong>⭐⭐⭐ De 3 à 4/5</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Visibilité <strong>standard</strong>. Vous recevez des offres régulièrement.</p><p style="margin:0.5rem 0 0;font-size:0.8rem;color:var(--vp-c-text-2);">Profil correct — des améliorations sont possibles.</p></div><div class="gi-value-card" style="border-color:var(--gi-tint-green-text);background:var(--gi-tint-green-bg);"><strong style="color:var(--gi-tint-green-text);">⭐⭐⭐⭐⭐ Plus de 4/5</strong><div style="margin:0.5rem 0;font-size:0.875rem;color:var(--gi-tint-green-text);font-weight:700;">🏆 Statut &quot;Top Distributeur&quot;</div><p style="margin:0;font-size:0.875rem;">Vos audiences s&#39;affichent en <strong>priorité</strong>. Vous recevez en premier les campagnes les plus qualifiées et les mieux rémunérées.</p></div></div><h2 id="les-7-criteres-d-evaluation" tabindex="-1">Les 7 critères d&#39;évaluation <a class="header-anchor" href="#les-7-criteres-d-evaluation" aria-label="Permalink to &quot;Les 7 critères d&#39;évaluation&quot;">​</a></h2><p>Votre score est calculé sur 7 dimensions. Voici comment les optimiser :</p><table tabindex="0"><thead><tr><th>Critère</th><th>Description</th><th>Comment progresser</th></tr></thead><tbody><tr><td><strong>1. Tarification</strong></td><td>Cohérence de vos CPM par rapport à la moyenne de votre secteur</td><td>Comparez-vous régulièrement aux distributeurs similaires</td></tr><tr><td><strong>2. Volume Semaine (Reach)</strong></td><td>Stabilité et importance de votre capacité de diffusion</td><td>Maintenez un volume régulier, évitez les pics/creux brusques</td></tr><tr><td><strong>3. Attractivité de la Marque</strong></td><td>Notoriété et image de votre enseigne sur son marché</td><td>Travaillez votre image de marque et complétez votre profil</td></tr><tr><td><strong>4. Fiabilité de l&#39;Inventaire</strong></td><td>Respect strict des volumes d&#39;insertion promis</td><td>Ne sur-engagez pas — mieux vaut promettre moins et tenir</td></tr><tr><td><strong>5. Réactivité de l&#39;Audience</strong></td><td>Performances réelles (taux de scan, conversions)</td><td>Ciblez bien vos campagnes selon votre audience réelle</td></tr><tr><td><strong>6. Historique de Campagnes</strong></td><td>Nombre de campagnes réussies via la plateforme</td><td>La fidélité est récompensée — continuez à opérer régulièrement</td></tr><tr><td><strong>7. Communication &amp; Reporting</strong></td><td>Réactivité aux demandes et ponctualité des déclarations</td><td>Déclarez vos volumes chaque lundi/mardi, répondez sous 48h</td></tr></tbody></table><h2 id="les-4-actions-qui-font-monter-le-score" tabindex="-1">Les 4 actions qui font monter le score <a class="header-anchor" href="#les-4-actions-qui-font-monter-le-score" aria-label="Permalink to &quot;Les 4 actions qui font monter le score&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>⏱️ Répondre en moins de 48h</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Acceptez ou déclinez les propositions rapidement. Évitez les refus systématiques sans proposer d&#39;alternative.</p></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>📊 Respecter les volumes engagés</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Distribuez exactement le volume promis. Fournissez vos reportings dans les délais (lundi/mardi).</p></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>💶 Maintenir un prix cohérent</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Vérifiez que vos CPM restent compétitifs et dans la fourchette de votre secteur.</p></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>🎯 Optimiser l&#39;engagement audience</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Acceptez les campagnes qui correspondent vraiment à votre audience — les taux de scan/clic impactent le score.</p></div></div><h2 id="ou-trouver-votre-score" tabindex="-1">Où trouver votre score ? <a class="header-anchor" href="#ou-trouver-votre-score" aria-label="Permalink to &quot;Où trouver votre score ?&quot;">​</a></h2><p>Votre score est visible dans votre espace distributeur :</p><p><strong>Mon Compte → Profil Distributeur → Score &amp; Réputation</strong></p><p>Vous y trouverez :</p><ul><li>Votre note actuelle sur 5</li><li>Le détail critère par critère</li><li>Les actions recommandées pour progresser</li></ul><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><p><strong>Mon score a baissé sans raison apparente — pourquoi ?</strong> Le score est recalculé dynamiquement. Une baisse peut indiquer : une déclaration de volume en retard, une campagne avec de mauvaises performances, ou un CPM qui est sorti de la fourchette de marché. Consultez le détail critère par critère dans votre profil.</p><p><strong>Est-ce qu&#39;un mauvais score peut me faire perdre des campagnes déjà acceptées ?</strong> Non. Les campagnes déjà acceptées et en cours ne sont pas affectées. Le score impacte uniquement les <em>futures</em> propositions que vous recevrez.</p><p><strong>Le score est-il visible par les annonceurs ?</strong> Oui. Les annonceurs voient votre note et le badge &quot;Top Distributeur&quot; si applicable. C&#39;est un signal de confiance qui facilite la sélection.</p><hr><p><strong>Prochaine étape :</strong> Gérez vos <a href="/handbook/publishers/audience-setup.html">audiences et données</a> pour attirer les campagnes les plus pertinentes.</p>',24)])])}const v=t(o,[["render",a]]);export{m as __pageData,v as default};
